/// <summary>
/// CW 방향 측정 핸들러 (Step 200~204)
/// CW 구동 → 전류 측정 → 정지 조건 판정 → 대기 → CCW 전환
/// </summary>
public class CwMeasureHandler : IStepHandler
{
    private readonly PowerSupplyService _supply;
    private readonly IoBoardService _ioBoard;
    private readonly IInspectionCallback _callback;

    public CwMeasureHandler(
        PowerSupplyService supply,
        IoBoardService ioBoard,
        IInspectionCallback callback)
    {
        _supply = supply;
        _ioBoard = ioBoard;
        _callback = callback;
    }

    public InspectionStep Execute(InspectionContext context)
    {
        switch (context.CurrentStep)
        {
            case InspectionStep.CwStart:
                return HandleCwStart(context);

            case InspectionStep.CwMeasure:
                return HandleCwMeasure(context);

            case InspectionStep.CwComplete:
                return HandleCwComplete(context);

            case InspectionStep.CwWait:
                return HandleCwWait(context);

            case InspectionStep.CwToCcw:
                return HandleCwToCcw(context);

            default:
                return context.CurrentStep;
        }
    }

    /// <summary>
    /// CW 구동 시작 — 모터 CW, 샘플 초기화
    /// </summary>
    private InspectionStep HandleCwStart(InspectionContext context)
    {
        _ioBoard.CW();
        _ioBoard.SendDoFrame();
        context.ResetSamples();
        _callback.RaiseLog($"CW 구동 시작 (반복 {context.TestCount + 1}/{context.TargetCount})");

        return InspectionStep.CwMeasure;
    }

    /// <summary>
    /// CW 전류 측정 — 정지 조건 확인
    /// </summary>
    private InspectionStep HandleCwMeasure(InspectionContext context)
    {
        double current = _supply.CurrentValue;
        double elapsed = context.ElapsedSeconds;
        double graphTime = context.GraphSeconds;

        // 샘플 기록
        context.CurrentSamples.Add(current);
        context.TimeSamples.Add(elapsed);
        _callback.RaiseDataPoint(graphTime, current);

        // 최대 전류 계산 (앞뒤 1초 제외)
        if (elapsed > 1.0)
        {
            // 끝쪽 1초 제외를 위해 매 루프 재계산
            context.MaxCurrent = CalculateMaxCurrent(context);
        }

        // 정지 조건 판정
        if (CheckStopCondition(context, current, elapsed))
        {
            return InspectionStep.CwComplete;
        }

        return InspectionStep.CwMeasure;
    }

    /// <summary>
    /// CW 완료 처리 — 결과 생성, 모터 OFF
    /// </summary>
    private InspectionStep HandleCwComplete(InspectionContext context)
    {
        // 최종 최대 전류 계산
        context.MaxCurrent = CalculateMaxCurrent(context);

        var result = new MeasureResult
        {
            SequenceNo = context.Results.Count + 1,
            Direction = "CW",
            Voltage = context.TargetVolt,
            MaxCurrent = context.MaxCurrent,
            ElapsedTime = context.ElapsedSeconds
        };

        context.Results.Add(result);
        _callback.RaiseResult(result);
        _callback.RaiseLog($"CW 완료 — 최대전류: {result.MaxCurrent:F3}A, 시간: {result.ElapsedTime:F1}s");

        _ioBoard.OFF();
        _ioBoard.SendDoFrame();
        context.StepTimer.Restart();

        return InspectionStep.CwWait;
    }

    /// <summary>
    /// CW 후 1초 대기
    /// </summary>
    private InspectionStep HandleCwWait(InspectionContext context)
    {
        if (context.ElapsedSeconds > 1.0)
        {
            return InspectionStep.CwToCcw;
        }
        return InspectionStep.CwWait;
    }

    /// <summary>
    /// CCW 전환 준비 — 타이머 재시작
    /// </summary>
    private static InspectionStep HandleCwToCcw(InspectionContext context)
    {
        context.StepTimer.Restart();
        return InspectionStep.CcwStart;
    }

    /// <summary>
    /// 정지 조건 확인
    /// </summary>
    private static bool CheckStopCondition(InspectionContext context, double current, double elapsed)
    {
        switch (context.StopMode)
        {
            case "CURRENT":
                // 전류 기준: 전류가 정지값 이상이고 1초 이상 경과
                return current >= context.StopValue && elapsed > 1.0;

            case "TIME":
                // 시간 기준: 경과 시간이 정지값 이상
                return elapsed >= context.StopValue;

            default:
                return false;
        }
    }

    /// <summary>
    /// 최대 전류 계산 — 앞 1초, 뒤 1초 구간 제외
    /// </summary>
    private static double CalculateMaxCurrent(InspectionContext context)
    {
        double maxCurrent = 0;
        double totalElapsed = context.ElapsedSeconds;

        for (int i = 0; i < context.TimeSamples.Count; i++)
        {
            double t = context.TimeSamples[i];
            // 앞 1초, 뒤 1초 구간 제외
            if (t > 1.0 && t < totalElapsed - 1.0)
            {
                if (context.CurrentSamples[i] > maxCurrent)
                {
                    maxCurrent = context.CurrentSamples[i];
                }
            }
        }

        return maxCurrent;
    }
}

